INSERT INTO questions (section, type, content, correct_answer, cefr_level, difficulty, competency_tag, aircraft_context, role_tag, active, is_latest, version_number) VALUES
-- Grammar (20)
('grammar','multiple_choice','The controller _____ the aircraft to hold at the current position.\nA) instructed\nB) was instructing\nC) instruct\nD) has instruct','A','A2','easy','tense_usage','general','atc',true,true,1),
('grammar','multiple_choice','Traffic information _____ issued to all aircraft in the vicinity.\nA) was\nB) were\nC) is\nD) are','A','B1','medium','passive_voice','general','atc',true,true,1),
('grammar','multiple_choice','If the separation _____ below minimum, an alert will be triggered.\nA) falls\nB) will fall\nC) fell\nD) has fallen','A','B1','medium','conditional_forms','general','atc',true,true,1),
('grammar','multiple_choice','All flight plans _____ be filed at least 60 minutes before departure.\nA) must\nB) can\nC) might\nD) would','A','A2','easy','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','The radar showed that two aircraft _____ converging on the same point.\nA) are\nB) were\nC) is\nD) has been','B','B1','medium','tense_usage','general','atc',true,true,1),
('grammar','fill_blank','Complete: The controller spoke _____ (calm) during the emergency.','calmly','A2','easy','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','Neither approach _____ departure control could establish contact with the aircraft.\nA) or\nB) and\nC) nor\nD) but','C','B1','medium','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','The runway _____ been cleared for the next arrival.\nA) has\nB) have\nC) is\nD) are','A','A2','easy','passive_voice','general','atc',true,true,1),
('grammar','multiple_choice','We should _____ coordinated with the adjacent sector earlier.\nA) had\nB) have\nC) has\nD) having','B','B2','medium','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','The pilot reported that the visibility _____ improving.\nA) is\nB) was\nC) were\nD) are','B','B1','medium','tense_usage','general','atc',true,true,1),
('grammar','fill_blank','Complete: Separation was maintained _____ (safe) throughout the procedure.','safely','B1','medium','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','_____ receiving the clearance, the pilot read it back incorrectly.\nA) After\nB) Before\nC) While\nD) During','A','B1','medium','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','The aircraft _____ be vectored around the restricted area.\nA) will\nB) shall\nC) would\nD) Both A and B','D','B1','medium','phraseology_grammar','general','atc',true,true,1),
('grammar','multiple_choice','Each controller _____ required to log all communications.\nA) is\nB) are\nC) were\nD) been','A','A2','easy','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','By the time the relief controller arrived, I _____ been on position for 3 hours.\nA) had\nB) have\nC) was\nD) am','A','B2','medium','tense_usage','general','atc',true,true,1),
('grammar','multiple_choice','The aircraft was cleared to land _____ the condition that it would exit at taxiway Alpha.\nA) on\nB) at\nC) in\nD) with','A','B2','hard','phraseology_grammar','general','atc',true,true,1),
('grammar','fill_blank','Complete: The frequency was _____ (heavy) congested during peak hours.','heavily','B1','medium','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','How _____ aircraft are currently in the holding pattern?\nA) many\nB) much\nC) some\nD) any','A','A2','easy','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','The pilot asked _____ he could be given a direct routing.\nA) that\nB) if\nC) what\nD) which','B','B1','medium','structural_accuracy','general','atc',true,true,1),
('grammar','multiple_choice','Clearances _____ never be assumed — always wait for explicit confirmation.\nA) should\nB) must\nC) can\nD) might','A','B1','medium','phraseology_grammar','general','atc',true,true,1),

-- Reading (10)
('reading','multiple_choice','Read the ATC procedure:\n\n"WAKE TURBULENCE SEPARATION MINIMUMS:\n- Heavy behind Super: 6 NM\n- Medium behind Heavy: 5 NM\n- Light behind Heavy: 6 NM\n- Light behind Medium: 4 NM\nThese minimums apply on approach within 10 NM of the runway threshold."\n\nWhat separation is required for a Medium aircraft following a Heavy?\nA) 4 NM\nB) 5 NM\nC) 6 NM\nD) 3 NM','B','B1','medium','technical_manual','general','atc',true,true,1),
('reading','multiple_choice','Read the shift briefing:\n\n"Today''s traffic: Expected 340 movements (180 departures, 160 arrivals). Runway 36L/18R active for arrivals, 36R/18L for departures. VOR DME RWY 36L is unserviceable — ILS only. Wind forecast: 360/15 becoming 020/20 after 1500 local. Expect runway change to 05 after 1600."\n\nWhich approach is NOT available today?\nA) ILS Runway 36L\nB) VOR DME Runway 36L\nC) Visual approach\nD) GPS approach','B','B1','medium','sop_comprehension','general','atc',true,true,1),
('reading','multiple_choice','Read the regulation:\n\n"ICAO Annex 11: Separation standards shall be applied between IFR flights in controlled airspace. The minimum radar separation in terminal airspace is 3 NM. In en-route airspace, the minimum is 5 NM. For non-radar environments, procedural separation standards apply."\n\nWhat is the minimum radar separation in terminal airspace?\nA) 2 NM\nB) 3 NM\nC) 5 NM\nD) 10 NM','B','B2','hard','technical_manual','general','atc',true,true,1),
('reading','multiple_choice','Read the incident report:\n\n"At 1423Z, aircraft TK123 was cleared to cross Runway 27 at intersection B4. Simultaneously, aircraft PC456 was on short final for Runway 27. The conflict was detected by the runway incursion monitoring system. TK123 was instructed to HOLD POSITION. PC456 was sent around. Minimum separation was 0.8 NM."\n\nWhat system detected the conflict?\nA) The pilot of PC456\nB) Runway incursion monitoring system\nC) TCAS\nD) The tower supervisor','B','B2','hard','incident_report','general','atc',true,true,1),
('reading','multiple_choice','Read the frequency assignment:\n\n"Istanbul Approach: 120.7 (North Sector), 121.1 (South Sector)\nIstanbul Tower: 118.1 (Runway 36L/18R), 118.7 (Runway 36R/18L)\nIstanbul Ground: 121.9 (North), 121.6 (South)\nIstanbul Delivery: 128.5"\n\nWhich frequency should a departing aircraft contact for clearance?\nA) 118.1\nB) 121.9\nC) 128.5\nD) 120.7','C','A2','easy','sop_comprehension','general','atc',true,true,1),
('reading','multiple_choice','Read the ATIS:\n\n"Istanbul Ataturk information Foxtrot, time 1400Z. Runway in use 36L. Wind 340 degrees 12 knots. Visibility 9999 metres. Cloud few 030, scattered 080. Temperature 18, dewpoint 11. QNH 1016. Transition level FL70. ILS approach in use. Advise on initial contact you have information Foxtrot."\n\nWhat information letter is current?\nA) Echo\nB) Foxtrot\nC) Golf\nD) Delta','B','A2','easy','weather_report_reading','general','atc',true,true,1),
('reading','multiple_choice','Read the coordination procedure:\n\n"All aircraft entering Ankara FIR from Istanbul FIR must be transferred to Ankara Control on 132.6 at least 10 minutes before the FIR boundary. Aircraft must be at their cleared level and on the correct airway. Any deviations must be coordinated by phone before transfer."\n\nWhen must aircraft be transferred to Ankara?\nA) At the FIR boundary\nB) 10 minutes before the boundary\nC) 5 minutes before\nD) When the pilot requests','B','B1','medium','sop_comprehension','general','atc',true,true,1),
('reading','multiple_choice','Read the emergency procedure:\n\n"COMMUNICATIONS FAILURE: If an aircraft fails to respond on the assigned frequency: 1) Try all available frequencies including 121.5 2) Request other aircraft to relay 3) Try phone contact via airline operations 4) If no contact within 5 minutes, implement lost communications procedures per local SOP."\n\nWhat is the universal emergency frequency?\nA) 118.1\nB) 121.5\nC) 132.4\nD) 128.5','B','B1','medium','sop_comprehension','general','atc',true,true,1),
('reading','multiple_choice','Read the staffing requirement:\n\n"Minimum staffing for Istanbul Tower during peak hours (0600-2200 local): 2 Tower Controllers, 1 Ground Controller, 1 Clearance Delivery, 1 Supervisor. During off-peak (2200-0600): 1 Tower, 1 Ground (combined Delivery), 1 Supervisor."\n\nHow many tower controllers are needed during peak hours?\nA) 1\nB) 2\nC) 3\nD) 4','B','A2','easy','sop_comprehension','general','atc',true,true,1),
('reading','multiple_choice','Read the noise abatement procedure:\n\n"Between 2300 and 0600 local time, all departures from Runway 36R must follow the NOISE 1 procedure: Climb at maximum rate to 3000ft AGL, then reduce to normal climb gradient. No turns below 1500ft AGL. Continuous climb preferred — avoid level-offs below FL100."\n\nWhat is the minimum altitude for turns during NOISE 1 procedure?\nA) 500ft AGL\nB) 1000ft AGL\nC) 1500ft AGL\nD) 3000ft AGL','C','B2','medium','sop_comprehension','general','atc',true,true,1),

-- Writing (8)
('writing','written_response','Write a brief incident report (at least 60 words) about a runway incursion: a vehicle entered Runway 27 without clearance while an aircraft was on short final. Describe what happened, what actions you took, and the outcome.','Model answer should include time, involved parties, immediate action (go-around), coordination with ground, safety investigation.','B2','hard','incident_report','general','atc',true,true,1),
('writing','written_response','Write a shift handover note (at least 50 words) for the incoming controller. Include traffic situation, weather trends, any equipment issues, and ongoing coordination.','Model answer should include traffic count, active runways, weather changes, equipment status, pending coordinations.','B1','medium','operational_message','general','atc',true,true,1),
('writing','written_response','An aircraft has declared PAN-PAN due to a sick passenger and requests priority landing. Write the coordination message (at least 50 words) you would send to approach control and emergency services.','Model answer should include aircraft callsign, type of emergency, request, coordination with approach/fire/ambulance.','B1','medium','operational_message','general','atc',true,true,1),
('writing','written_response','Write a safety report (at least 60 words) about a near-miss between two aircraft on crossing taxiways. Include contributing factors and your recommendation to prevent recurrence.','Model answer should include factual description, separation lost, contributing factors, recommendation for signage/procedures.','B2','hard','safety_report','general','atc',true,true,1),
('writing','written_response','Write an email (at least 50 words) to the airport authority requesting that faded taxiway markings at intersection Alpha-3 be repainted. Explain the safety concern and urgency.','Model answer should include specific location, safety risk, near-miss potential, request timeline.','A2','easy','operational_message','general','atc',true,true,1),
('writing','written_response','A pilot has filed a complaint that they were kept in a hold for 35 minutes unnecessarily. Write a professional response (at least 60 words) explaining the reason for the hold (weather below minimums, traffic congestion).','Model answer should be professional, factual, explain weather/traffic situation, express understanding.','B2','medium','passenger_complaint','general','atc',true,true,1),
('writing','written_response','Write a brief training note (at least 50 words) explaining to a new controller what "sterile cockpit" means and why controllers should minimize unnecessary communications during critical phases of flight.','Model answer should define sterile cockpit, explain below 10000ft rule, impact on pilot workload, controller best practices.','B1','medium','technical_description','general','atc',true,true,1),
('writing','written_response','Write a proposal (at least 60 words) suggesting a new standard taxi route to reduce ground conflicts at your airport. Describe the current problem and your solution.','Model answer should include current conflict hotspot, proposed routing change, expected safety improvement, implementation suggestion.','B2','hard','operational_message','general','atc',true,true,1),

-- Speaking (8)
('speaking','audio_response','Issue ATC clearance to Turkish Airlines flight 1923 for departure: Runway 36L, ROMEO 1 ALPHA departure, climb FL180, squawk 4512, contact departure on 119.7.\n\nSpeak clearly using standard ATC phraseology.','Expected: Standard format, correct phraseology, runway, SID, altitude, squawk, frequency handoff.','B1','medium','atc_phraseology','general','atc',true,true,1),
('speaking','audio_response','An aircraft reports an engine failure after takeoff. Issue emergency instructions: clear the airspace, vector the aircraft for an immediate return, coordinate with emergency services.\n\nSpeak for at least 40 seconds.','Expected: Calm delivery, MAYDAY acknowledgment, priority handling, vectors, crash/fire alert, runway clearance.','B2','hard','roleplay_emergency','general','atc',true,true,1),
('speaking','audio_response','Explain what a "go-around" is, when a controller might instruct it, and what happens after. Use examples.\n\nSpeak for at least 40 seconds.','Expected: Definition, reasons (traffic, weather, runway occupied), procedure, new instructions, safety importance.','B1','medium','oral_briefing','general','atc',true,true,1),
('speaking','audio_response','You are handing over your position to the next controller. Brief them on: current traffic picture, weather, any ongoing situations, and anything to watch out for.\n\nSpeak for at least 45 seconds.','Expected: Structured handover, traffic count/positions, weather trend, special situations, equipment status.','B1','medium','crew_coordination','general','atc',true,true,1),
('speaking','audio_response','Issue taxi instructions to Pegasus flight 247 from Gate 22 to Runway 36L via taxiways Charlie, Alpha, and hold short of Runway 27 crossing.\n\nSpeak clearly using standard phraseology.','Expected: Correct callsign, specific taxi route, hold short instruction, readback expected.','A2','easy','atc_phraseology','general','atc',true,true,1),
('speaking','audio_response','Two aircraft are converging and you notice a potential conflict. Describe what you would do step by step to resolve the situation.\n\nSpeak for at least 40 seconds.','Expected: Identify conflict, issue immediate instruction (turn/climb/descend), traffic information, monitor, report.','B2','hard','roleplay_emergency','general','atc',true,true,1),
('speaking','audio_response','Explain the importance of read-back in ATC communications. Why is it critical? What happens when a read-back is incorrect?\n\nSpeak for at least 30 seconds.','Expected: Read-back purpose, error prevention, hear-back verification, examples of critical clearances.','B1','medium','oral_briefing','general','atc',true,true,1),
('speaking','audio_response','Roleplay: A pilot is requesting a shortcut — direct routing to save fuel. However, there is restricted airspace in the way. Deny the request professionally and offer an alternative.\n\nSpeak for at least 30 seconds.','Expected: Professional denial, reason (restricted area), alternative routing offered, helpful tone.','B1','medium','roleplay_atc','general','atc',true,true,1),

-- Listening (12)
('listening','multiple_choice','[AUDIO] "Istanbul Tower, Pegasus 245, ready for departure Runway 36 Left."\n"Pegasus 245, Istanbul Tower, wind 350 degrees 14 knots, Runway 36 Left, cleared for takeoff."\n\nWhat wind direction is reported?\nA) 250 degrees\nB) 350 degrees\nC) 360 degrees\nD) 140 degrees','B','A2','easy','atc_phraseology','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Approach, Turkish 1901, we have traffic on TCAS — appears to be same level, 12 o''clock, 5 miles."\n"Turkish 1901, roger, that is Pegasus 502, climbing to FL240, no conflict, he will be above you shortly."\n\nWhat is the other aircraft doing?\nA) Descending\nB) Climbing to FL240\nC) Landing\nD) Holding','B','B1','medium','atc_phraseology','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "All stations, Istanbul Approach. Runway 36 Left is now closed due to a disabled aircraft. All arrivals will use Runway 36 Right ILS approach. Expect delays of 15 to 20 minutes."\n\nWhy is the runway closed?\nA) Construction\nB) A disabled aircraft\nC) Weather\nD) Scheduled maintenance','B','B1','medium','emergency_broadcast','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Ground, SunExpress 302 at holding point Alpha 1, ready for departure."\n"SunExpress 302, hold position. Landing traffic Runway 27. I say again, HOLD POSITION."\n\nWhat must the pilot do?\nA) Enter the runway\nB) Hold position and wait\nC) Take off immediately\nD) Taxi back to the gate','B','A2','easy','atc_phraseology','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Istanbul Delivery, AnadoluJet 670, requesting IFR clearance to Ankara, information Delta."\n"AnadoluJet 670, cleared to Ankara via KEMIK 2 BRAVO departure. Climb initially 5000 feet, expect FL310 10 minutes after departure. Squawk 3245."\n\nWhat is the initial climb altitude?\nA) 3000 feet\nB) 5000 feet\nC) FL310\nD) FL100','B','B1','medium','atc_phraseology','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Pan-Pan, Pan-Pan, Pan-Pan. Istanbul Approach, this is Atlas 891. We have a pressurization problem. Requesting descent to FL100 and priority approach."\n"Atlas 891, roger your Pan-Pan. Descend FL100. You are number 1 for approach. Emergency services on standby."\n\nWhat type of emergency is this?\nA) MAYDAY — immediate danger\nB) PAN-PAN — urgency\nC) No emergency\nD) Distress signal','B','B1','medium','emergency_broadcast','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Tower supervisor to all positions: we are now implementing low visibility procedures. RVR Runway 36L is 350 metres. Only CAT III equipped aircraft will be accepted for approach. Increase departure spacing to 3 minutes. Acknowledge."\n\nWhat is the current RVR?\nA) 550 metres\nB) 350 metres\nC) 1000 metres\nD) 3 metres','B','B2','hard','ground_ops_radio','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Istanbul Ground, Freebird 412, request taxi to the international terminal, Gate 15."\n"Freebird 412, taxi via taxiway Bravo, Charlie, hold short of runway 27 at Charlie 4."\n\nWhere must the aircraft hold?\nA) At Gate 15\nB) At Charlie 4 before Runway 27\nC) At the terminal\nD) At Bravo','B','A2','easy','atc_phraseology','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Ankara Center, Turkish 2023, request direct to ROMEO waypoint to save fuel. We are currently on the ALPHA 1 airway."\n"Turkish 2023, negative direct ROMEO. Restricted area TRA-15 is active. Suggest continue on ALPHA 1 airway and expect direct ROMEO after passing waypoint SIERRA."\n\nWhy was the direct route denied?\nA) Bad weather\nB) Restricted area is active\nC) Traffic conflict\nD) Runway closure','B','B1','medium','atc_phraseology','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "All stations, ATIS update. Istanbul Airport information Golf, time 1600Z. Runway change in effect. Departures now Runway 05, arrivals Runway 05. Wind 050 degrees 18 knots. Transition level now FL80. All aircraft acknowledge new ATIS on initial contact."\n\nWhat has changed?\nA) The weather improved\nB) Runway direction has changed to 05\nC) The airport is closing\nD) New aircraft parking','B','B1','medium','atc_phraseology','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Shift supervisor to tower: I just received a phone call from the military. They are activating restricted area TRA-22 effective in 30 minutes, from FL200 to unlimited, for 2 hours. Please ensure all traffic is routed clear."\n\nHow long will the restricted area be active?\nA) 30 minutes\nB) 1 hour\nC) 2 hours\nD) Until further notice','C','B2','medium','ground_ops_radio','general','atc',true,true,1),
('listening','multiple_choice','[AUDIO] "Controller handover briefing: You have 8 aircraft on frequency — 3 arrivals sequenced for 36L, 2 departures holding at Alpha and Bravo, and 3 overflights at FL350-FL370. Weather is stable. The ILS is on test — it may drop out briefly, so have visual approach ready as backup."\n\nHow many aircraft are on frequency?\nA) 5\nB) 6\nC) 8\nD) 10','C','B1','medium','crew_coordination','general','atc',true,true,1);
